 1	import * as React from 'react';
 2	import Helmet from 'react-helmet';
 3	import {
 4	  Button,
 5	  Modal,
 6	  ModalBox,
 7	  ModalBoxHeader,
 8	  ModalBoxBody,
 9	  ModalBoxFooter,
10	  ButtonVariant,
11	} from '@patternfly/react-core';
12	import { useTranslation } from 'react-i18next';
13	import { ResourceYAMLEditor, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
14	import resourceGVKMapping from '../utils/latest';
15	
16	const KuadrantAuthPolicyCreatePage: React.FC = () => {
17	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
18	  const [selectedNamespace] = useActiveNamespace();
19	
20	  const yamlResource = {
21	    apiVersion:
22	      resourceGVKMapping['AuthPolicy'].group + '/' + resourceGVKMapping['AuthPolicy'].version,
23	    kind: resourceGVKMapping['AuthPolicy'].kind,
24	    metadata: {
25	      name: 'example-authpolicy',
26	      namespace: selectedNamespace,
27	    },
28	    spec: {
29	      rules: {
30	        authorization: {
31	          denyAll: {
32	            opa: {
33	              rego: 'allow = false',
34	            },
35	          },
36	        },
37	        response: {
38	          unauthorized: {
39	            body: {
40	              value: JSON.stringify(
41	                {
42	                  error: 'Forbidden',
43	                  message: 'Access denied by default. Create a specific auth policy for the route.',
44	                },
45	                null,
46	                2,
47	              ),
48	            },
49	            headers: {
50	              'content-type': {
51	                value: 'application/json',
52	              },
53	            },
54	          },
55	        },
56	      },
57	      targetRef: {
58	        group: 'gateway.networking.k8s.io',
59	        kind: 'Gateway',
60	        name: 'prod-web',
61	      },
62	    },
63	  };
64	
65	  const [isErrorModalOpen, setIsErrorModalOpen] = React.useState(false);
66	  const [errorModalMsg] = React.useState('');
67	
68	  return (
69	    <>
70	      <Helmet>
71	        <title>{t('Create AuthPolicy')}</title>
72	      </Helmet>
73	
74	      <ResourceYAMLEditor initialResource={yamlResource} header="Create AuthPolicy" create={true} />
75	
76	      <Modal isOpen={isErrorModalOpen} onClose={() => setIsErrorModalOpen(false)} variant="medium">
77	        <ModalBox aria-labelledby="error-modal-title" aria-describedby="error-modal-description">
78	          <ModalBoxHeader>{t('Error creating AuthPolicy')}</ModalBoxHeader>
79	          <ModalBoxBody id="error-modal-description">
80	            <b>{errorModalMsg}</b>
81	          </ModalBoxBody>
82	          <ModalBoxFooter>
83	            <Button
84	              key="ok"
85	              variant={ButtonVariant.link}
86	              onClick={() => setIsErrorModalOpen(false)}
87	            >
88	              OK
89	            </Button>
90	          </ModalBoxFooter>
91	        </ModalBox>
92	      </Modal>
93	    </>
94	  );
95	};
96	
97	export default KuadrantAuthPolicyCreatePage;

